import{_ as o,o as i,c as r,a4 as a}from"./chunks/framework.EYT3XhWU.js";const p=JSON.parse('{"title":"开篇","description":"","frontmatter":{},"headers":[],"relativePath":"行测/资料分析/开篇.md","filePath":"行测/资料分析/开篇.md"}'),e={name:"行测/资料分析/开篇.md"};function t(n,l,s,c,d,g){return i(),r("div",null,[...l[0]||(l[0]=[a('<h1 id="开篇" tabindex="-1">开篇 <a class="header-anchor" href="#开篇" aria-label="Permalink to “开篇”">​</a></h1><p>字数: 3226 字 时长: 12 分钟 <strong>VIP文档</strong></p><h3 id="一、五年规划" tabindex="-1">一、五年规划 <a class="header-anchor" href="#一、五年规划" aria-label="Permalink to “一、五年规划”">​</a></h3><ol><li>全称为中华人民共和国国民经济和社会发展五年规划纲要，是中国国民经济计划的重要部分，属长期计划。主要是对国家重大建设项目、生产力分布和国民经济重要比例关系等作出规划，为国民经济发展远景规定目标和方向。中国从1953年开始制定第一个“五年计划”。从“十一五”起，“五年计划”改为“五年规划”。 <ol><li>（1）十一五：2006年~2010年</li><li>（2）十二五：2011年~2015年</li><li>（3）十三五：2016年~2020年</li><li>（4）十四五：2021年~2025年</li></ol></li></ol><h3 id="二、基期量与现期量" tabindex="-1">二、基期量与现期量 <a class="header-anchor" href="#二、基期量与现期量" aria-label="Permalink to “二、基期量与现期量”">​</a></h3><ol><li><strong>1、现期</strong>：我们所要研究的、用来和基期进行对比的那个时期。也就是“当前”的、我们更关心的时期。 <ol><li><code>例</code>：①分析公司2024年的销售额增长率，2024年就是现期。②2023年比2021年收入增长了10%。这里 2023年就是现期。</li></ol></li><li><strong>2、现期量</strong>：在现期这个时间点上的具体数值。通常用符号 A 表示。公式：现期量 = 基期量 + 增长量 = 基期量 × (1 + 增长率) <ol><li><code>例</code>：2024年的销售额是1200万元，2023年（基期）的销售额是1000万元，分析2024年的销售额的增长率。那么2024年是现期，1200万元就是现期量。</li></ol></li><li><strong>3、基期</strong>：作为对比参照物的时期。比如像一把尺子的“0刻度”，你想要知道变化了多少，总得有个起点，这个起点就是基期。 <ol><li><code>例</code>：①分析公司2024年的销售额增长，那么2023年通常会被选为基期。②2023年比2021年收入增长了10%。这里 2021年就是基期。</li></ol></li><li><strong>4、基期量</strong>：在基期这个特定时间点或时间段内，某个指标的具体数值。通常用符号 B 表示。公式：基期量 = 现期量 - 增长量 = 现期量1+增长率 <ol><li><code>例</code>：2024年的销售额是1200万元，2023年（基期）的销售额是1000万元，分析2024年的销售额的增长率。那么2023年是基期，1000万元就是基期量。</li></ol></li></ol><h3 id="三、增长量与增长率" tabindex="-1">三、增长量与增长率 <a class="header-anchor" href="#三、增长量与增长率" aria-label="Permalink to “三、增长量与增长率”">​</a></h3><ol><li><strong>1、增长量</strong>：就是在某个时间段内，现期量相对于基期量的绝对变化量。它表示实际增加了多少或减少了多少。这个变化量是通过现期量减去基期量来计算，如果结果是正数，说明增加了；如果是负数，那就说明减少了。</li><li><strong>2、增长量公式</strong>：增长量 = 现期量 - 基期量 = 基期量×增长率 = 现期量增长率×增长率 <ol><li><code>例</code>：2024年的销售额是1200万元，2023年的销售额是1000万元。求2024相对2023的增长量？【销售额增长量 = 1200万元 - 1000万元 = 200万元 (增长了200万元)】</li><li><code>例</code>：2024年的销售额的增长率为-10%，2023年的销售额是1200万元。求2024相对2023的增长量？【销售额增长量 = 1200万元 ×（-10%） = -120万元 (减少了120万元)】</li></ol></li><li><strong>3、增长率</strong>：现期量相对于基期量的相对变化程度，通常用百分比(%)表示。即在基期量的基础上增长了多大的幅度。结果可正可负。正数表示增长率（如增长20%），负数表示下降率（如下降10%）。 <ol><li>（1）增长率又称增幅、增速、增长幅度、增长速度等。</li><li>（2）增长率一般用 r 字母代表（rate 的简写）</li><li>（3）“减少率或下降幅度”本质是一种未带负号的“增长率”</li></ol></li><li><strong>4、增长率公式</strong>：增长率=增长量基期量=增长量现期量增长量=现期量基期量基期量=现期量基期量 - 1</li><li><strong>5、增长率读数比较</strong>： <ol><li>（1）增幅、增速、增长率比较的时候需要看正负号；</li><li>（2）变化幅度、涨跌幅比较的时候只需要看绝对值；</li><li>（3）降幅比较的时候，首先一定得是下降（负数）的，再看绝对值。</li></ol></li><li><strong>6、概念混淆</strong>： <ol><li>（1）问增长最多 → 比较增长量</li><li>（2）问增长最快 → 比较增长率</li></ol></li></ol><h3 id="四、同比、环比" tabindex="-1">四、同比、环比 <a class="header-anchor" href="#四、同比、环比" aria-label="Permalink to “四、同比、环比”">​</a></h3><ul><li><strong>1、同比</strong>：同比是以上年同期为基期相比较，即本期某一时间段（点）与上年相同时间段（点）相比，可以理解为今年第n月与去年第n月的比较。 <ul><li><code>例</code>：2025年1月的同比就是2024年1月。2025年的同比就是2024年。2025年第二季度的同比就是2024年第二季度。</li></ul></li><li><strong>2、环比</strong>：环比是与上一个相邻统计周期相比较，表明统计指标逐期的发展变化，可以理解为第n月与第n-1月的比较。 <ul><li><code>例</code>：2025年1月的环比就是2024年12月。2025年的环比就是2024年。2025年第二季度的环比就是2025年第一季度。</li></ul></li></ul><h3 id="五、名义和实际增长率" tabindex="-1">五、名义和实际增长率 <a class="header-anchor" href="#五、名义和实际增长率" aria-label="Permalink to “五、名义和实际增长率”">​</a></h3><ul><li><blockquote><p>在实际应用中，比如江苏省考和山东省考的题目中，经常会涉及到这两个概念的区别。</p></blockquote></li><li><blockquote><p>一般这两个名词常常出现在涉及居民收入、社会消费品零售额等领域的材料中，在表述上会有“名义增长……”、“扣除价格因素，实际增长……”等字样。题干中会有“按照XX年的价格计算，……”字样。我们接触到的增长率如果没有特殊说明，则都是名义增长率。只有特殊写明“扣除价格因素”或“实际增速”等字样，才是实际增长率。</p></blockquote></li><li><p><strong>1、名义增长率</strong>：没有扣除价格因素影响得到的增长率。 （<code>一般用这个算增长率</code>）</p></li><li><p><strong>2、实际增长率</strong>：扣除价格因素影响得到的增长率。</p></li><li><p><strong>3、计算公式</strong>：名义增长率=实际增长率+通货膨胀率。一般不会考如何换算、如何扣除价格因素。一般都是直接给定名义增速和实际增速，求按照实际增速计算的现期量或增长量。</p><ul><li><code>举例</code>：假设去年我的年薪为100元，今年我的年薪为120元。根据公式：增长率=(现期量-基期量)/基期量=20%，该增长率为“名义增长率”；但实际情况由于通货膨胀，今年的100元相较于去年的100元购买力有所下降，故我工资增的增速并没有代表我实际购买力的增速，由此可知实际增长率略小于名义增长率。当实际增长率大于名义增长率，则说明发生了通货紧缩。</li></ul></li><li><p><strong>4、例</strong>：2018年1—12月，社会消费品零售总额380987亿元，比上年增长9.0%（扣除价格因素实际增长6.9%，以下除特殊说明外均为名义增长）。按2017年价格计算2018年社会消费品零售总额约为多少？</p><ul><li><code>分析</code>：“按2017年价格计算”，即扣除2018年价格上涨因素造成的增长，也就是按2017年的实际增长率来计算。先计算2017年的社会消费品零售额为380987÷（1+9%）（亿元），再利用公式现期量=基期量×（1+增长率）以及实际增长率的数值6.9%来计算，得到按2017年价格计算的2018年社会消费品零售总额为380987÷（1+9%）×（1+6.9%）≈38.1×（1+6.9%）÷（1+9%）万亿≈38.1×（1-2%）万亿≈37.3万亿，按2017年价格计算2018年社会消费品零售总额约373000。</li></ul></li></ul><h3 id="六、比重、平均数、倍数" tabindex="-1">六、比重、平均数、倍数 <a class="header-anchor" href="#六、比重、平均数、倍数" aria-label="Permalink to “六、比重、平均数、倍数”">​</a></h3><ol><li><p>在资料分析中，比重、平均数、倍数是三个核心基础概念，它们本质上都是除法关系（A÷B），但描述的场景和含义不同。</p><ol><li>比重：部分是整体的百分之几（部分/整体）。</li><li>平均数：总数分给份数，每个份得多少（总数/份数）。</li><li>倍数：一个量是另一个量的几倍（A/B）。</li></ol></li><li><p><strong>1、比重</strong>：指某部分在总体中所占的份额，通常用百分数（%）表示。核心公式 比重 = 部分量 ÷ 整体量 × 100%。因为 部分量 ≤ 整体量，所以 比重 ≤ 100%。</p><ol><li><blockquote><p>例子：某班有50人（整体），男生有30人（部分）。男生所占比重 = 30 ÷ 50 = 60%。</p></blockquote></li></ol></li><li><p><strong>2、平均数</strong>：反映一组数据的平均水平，即把总数平均分配到每个份上。核心公式 平均数 = 总数 ÷ 份数。平均数没有上限，可以是任何数值，且通常带有单位（如元、吨、公里/小时）。</p><ol><li><blockquote><p>例子：某商店3天总营业额3000元（总数），平均每天的营业额 = 3000 ÷ 3 = 1000元/天。</p></blockquote></li></ol></li><li><p><strong>3、倍数</strong>：表示两个量之间的比值关系，表明一个量是另一个量的几倍。核心公式 倍数 = A ÷ B。倍数可以大于、等于或小于1（小于1时也可说成“几分之几”）。<code>注意区分“翻番”：翻一番是变为2倍，翻两番是变为4倍</code></p><ol><li><blockquote><p>例子：甲厂产值2000万，乙厂产值500万。甲是乙的倍数 = 2000 ÷ 500 = 4倍。</p></blockquote></li></ol></li></ol><h3 id="七、人口相关" tabindex="-1">七、人口相关 <a class="header-anchor" href="#七、人口相关" aria-label="Permalink to “七、人口相关”">​</a></h3><ul><li><strong>1、出生率</strong> = 年出生人数年平均人数×1000‰</li><li><strong>2、死亡率</strong> = 年死亡人数年平均人数×1000‰ <ul><li><code>平均人口数＝（年初人口数＋年末人口数）÷2</code></li></ul></li><li><strong>3、自然增长人口</strong> = 出生人口 - 死亡人口</li><li><strong>4、自然增长率</strong> = 出生率 - 死亡率</li><li><strong>5、城镇化率</strong> = 城镇人口总人口 ×100%</li></ul><h3 id="八、三大产业" tabindex="-1">八、三大产业 <a class="header-anchor" href="#八、三大产业" aria-label="Permalink to “八、三大产业”">​</a></h3><ol><li><strong>1、第一产业（农业）</strong>：指农、林、牧、渔业（不含农、林、牧、渔、服务业）。</li><li><strong>2、第二产业（工业和建筑业）</strong>：是指采矿业（不含开采辅助活动），制造业（不含金属制品、机械和设备修理业），电力、热力、燃气及水生产和供应业，建筑业。</li><li><strong>3、第三产业</strong>：指除第一、二产业以外的其他行业。</li></ol><h3 id="九、贸易相关" tabindex="-1">九、贸易相关 <a class="header-anchor" href="#九、贸易相关" aria-label="Permalink to “九、贸易相关”">​</a></h3><ul><li><strong>1、货物周转量</strong> = 货物运输量 × 运输距离（单位一般为 吨公里）</li><li><strong>2、进出口</strong> = 进口 + 出口</li><li><strong>3、贸易顺差</strong> = 出口 - 进口 （<code>出口&gt;进口</code>）</li><li><strong>4、贸易逆差</strong> = 进口 - 出口 （<code>出口&lt;进口</code>）</li><li><code>理解：出口就是赚钱，进口就是花钱，赚的钱比花的钱多，就是顺。</code></li></ul><p>拓展：利润率的计算</p><ol><li><p>资料分析中，利润率=利润 ÷ 收入</p></li><li><p>数量关系中，利润率=利润 ÷ 成本</p></li><li><p>原因：资料分析一般是宏观的数据，比如第一产业的成本是无法计算的，所计算的利润率是收入利润率；而数量关系中商家往往可以计算出成本，因此是成本利润率。</p></li><li><blockquote><p>例题：2015年江西省规模以上工业企业实现主营业务收入32459.4亿元，比上年增长4.3%；实现利税总额3543.8亿元，增长3.8%，其中，利润总额2128.0亿元，增长2.4%。主营业务收入超百亿元的企业10户，其中，江铜集团2010.4亿元，居全省首位。 问：2015年江西省规模以上工业企业的营业利润率与上年同期相比（ ） A.有所上升 B.有所下降  C.持平 D.无法判断 分析：利润率=利润 ÷ 收入。由题干“2015年江西省规模以上工业企业的营业利润率与上年同期相比”，结合选项，可知本题为两期比重的比较问题，仅需比较增长率与的大小关系即可。根据“利润总额” “主营业务收入”定位材料，定位数据：a=利润总额的增长率=2.4%，b=主营业务收入增长率=4.3%，a＜b，即2015年江西省规模以上工业企业的营业利润率低于上年同期。故正确答案为B。</p></blockquote></li></ol><h3 id="十、gdp、gnp" tabindex="-1">十、GDP、GNP <a class="header-anchor" href="#十、gdp、gnp" aria-label="Permalink to “十、GDP、GNP”">​</a></h3><ul><li><strong>1、GDP</strong>：国内生产总值，一个国家或地区当年所生产出的全部最终产品和劳务的价值（第一产业 + 第二产业 + 第三产业）</li><li><strong>2、GNP</strong>：国民生产总值，一个国家或地区所有国民当年生产的总值， 不论在国内还是国外</li></ul><h3 id="十一、恩格尔系数与基尼系数" tabindex="-1">十一、恩格尔系数与基尼系数 <a class="header-anchor" href="#十一、恩格尔系数与基尼系数" aria-label="Permalink to “十一、恩格尔系数与基尼系数”">​</a></h3><ol><li><strong>1、恩格尔系数</strong>：食品支出总额占个人消费支出总额的比重。（食物支出金额 / 总支出金额 × 100%‌）这个比例越低，反应生活水平越高。</li><li><strong>2、基尼系数</strong>：指国际上通用的、用以衡量一个国家或地区居民收入差距的常用指标。基尼系数介于 0-1 之间，基尼系数越大，表示不平等程度越高。</li></ol>',26)])])}const b=o(e,[["render",t]]);export{p as __pageData,b as default};
